import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { hallAPI } from '../services/api';

const initialForm = {
  hallId: '',
  name: '',
  capacity: 30,
  building: '',
  floor: 1,
  facilities: '',
  isAvailable: true,
};

const Halls = () => {
  const [halls, setHalls] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState(initialForm);

  const fetchHalls = async () => {
    try {
      setLoading(true);
      const response = await hallAPI.getAll();
      setHalls(response.data || []);
    } catch (error) {
      toast.error('Failed to load halls');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHalls();
  }, []);

  const onChange = (event) => {
    const { name, value, type, checked } = event.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleAddHall = async (event) => {
    event.preventDefault();
    try {
      setSubmitting(true);
      const payload = {
        ...formData,
        capacity: Number(formData.capacity),
        floor: Number(formData.floor),
        facilities: formData.facilities
          .split(',')
          .map((facility) => facility.trim())
          .filter(Boolean),
      };
      await hallAPI.add(payload);
      toast.success('Hall added successfully');
      setFormData(initialForm);
      fetchHalls();
    } catch (error) {
      toast.error(error.response?.data?.error || 'Failed to add hall');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteHall = async (hallId) => {
    try {
      await hallAPI.delete(hallId);
      toast.success('Hall deleted');
      fetchHalls();
    } catch (error) {
      toast.error('Failed to delete hall');
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Exam Halls</h1>
        <p className="text-gray-600">Configure available halls and capacities.</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Add Hall</h2>
        <form onSubmit={handleAddHall} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <input
            className="input-field"
            name="hallId"
            placeholder="Hall ID"
            value={formData.hallId}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="name"
            placeholder="Hall Name"
            value={formData.name}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="number"
            min="1"
            name="capacity"
            placeholder="Capacity"
            value={formData.capacity}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="building"
            placeholder="Building"
            value={formData.building}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="number"
            min="0"
            name="floor"
            placeholder="Floor"
            value={formData.floor}
            onChange={onChange}
          />
          <input
            className="input-field"
            name="facilities"
            placeholder="Facilities (comma separated)"
            value={formData.facilities}
            onChange={onChange}
          />
          <label className="flex items-center space-x-2 md:col-span-2 lg:col-span-1">
            <input
              type="checkbox"
              name="isAvailable"
              checked={formData.isAvailable}
              onChange={onChange}
            />
            <span className="text-gray-700">Available for scheduling</span>
          </label>
          <div className="md:col-span-2 lg:col-span-3">
            <button type="submit" className="btn-primary" disabled={submitting}>
              {submitting ? 'Adding...' : 'Add Hall'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6 overflow-x-auto">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-800">Hall List</h2>
          <button onClick={fetchHalls} className="btn-secondary">
            Refresh
          </button>
        </div>

        {loading ? (
          <p className="text-gray-500">Loading halls...</p>
        ) : halls.length === 0 ? (
          <p className="text-gray-500">No halls added yet.</p>
        ) : (
          <table className="min-w-full">
            <thead>
              <tr className="table-header">
                <th className="px-4 py-3 text-left">Hall ID</th>
                <th className="px-4 py-3 text-left">Name</th>
                <th className="px-4 py-3 text-left">Building</th>
                <th className="px-4 py-3 text-left">Capacity</th>
                <th className="px-4 py-3 text-left">Status</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {halls.map((hall) => (
                <tr key={hall.hallId} className="table-row">
                  <td className="px-4 py-3 font-semibold">{hall.hallId}</td>
                  <td className="px-4 py-3">{hall.name}</td>
                  <td className="px-4 py-3">
                    {hall.building} (Floor {hall.floor})
                  </td>
                  <td className="px-4 py-3">{hall.capacity}</td>
                  <td className="px-4 py-3">
                    <span className={hall.isAvailable ? 'text-green-600' : 'text-red-600'}>
                      {hall.isAvailable ? 'Available' : 'Unavailable'}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <button
                      onClick={() => handleDeleteHall(hall.hallId)}
                      className="btn-danger"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Halls;
